Fn::Sub:
{
  "Comment": "pp-kitchen v3 — workflow enriquecido con Choice, Parallel, Wait, Retry, Catch",
  "StartAt": "ValidarPedido",
  "States": {
    "ValidarPedido": {
      "Type": "Choice",
      "Choices": [
        {
          "Variable": "$.orderId",
          "IsPresent": true,
          "Next": "RegistrarRecepcion"
        }
      ],
      "Default": "PedidoInvalido"
    },
    "PedidoInvalido": {
      "Type": "Fail",
      "Error": "PedidoInvalido",
      "Cause": "El pedido no tiene orderId"
    },
    "RegistrarRecepcion": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "RECIBIDO"
        }
      },
      "Retry": [
        {
          "ErrorEquals": [
            "Lambda.ServiceException",
            "Lambda.AWSLambdaException"
          ],
          "IntervalSeconds": 2,
          "MaxAttempts": 3,
          "BackoffRate": 2
        }
      ],
      "Catch": [
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "Next": "ErrorGeneral",
          "ResultPath": "$.error"
        }
      ],
      "Next": "PreparacionParalela",
      "ResultPath": null
    },
    "PreparacionParalela": {
      "Type": "Parallel",
      "Branches": [
        {
          "StartAt": "NotificarCocina",
          "States": {
            "NotificarCocina": {
              "Type": "Wait",
              "Seconds": 2,
              "Next": "CocinaLista"
            },
            "CocinaLista": {
              "Type": "Pass",
              "Result": {
                "preparacion": "cocina_lista"
              },
              "End": true
            }
          }
        },
        {
          "StartAt": "NotificarAlmacen",
          "States": {
            "NotificarAlmacen": {
              "Type": "Wait",
              "Seconds": 1,
              "Next": "AlmacenListo"
            },
            "AlmacenListo": {
              "Type": "Pass",
              "Result": {
                "preparacion": "almacen_listo"
              },
              "End": true
            }
          }
        }
      ],
      "Next": "EN_COCINA",
      "ResultPath": null
    },
    "EN_COCINA": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke.waitForTaskToken",
      "Parameters": {
        "FunctionName": "${d017b02987a60784aa244e16617956a7}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "EN_COCINA",
          "workerId.$": "$.workerId",
          "taskToken.$": "$$.Task.Token"
        }
      },
      "Retry": [
        {
          "ErrorEquals": [
            "Lambda.ServiceException"
          ],
          "IntervalSeconds": 2,
          "MaxAttempts": 2,
          "BackoffRate": 2
        }
      ],
      "Catch": [
        {
          "ErrorEquals": [
            "States.HeartbeatTimeout"
          ],
          "Next": "TimeoutCocina",
          "ResultPath": "$.error"
        },
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "Next": "ErrorGeneral",
          "ResultPath": "$.error"
        }
      ],
      "HeartbeatSeconds": 3600,
      "Next": "EmitirCocinaCompleta",
      "ResultPath": null
    },
    "TimeoutCocina": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "TIMEOUT_COCINA"
        }
      },
      "Next": "EN_COCINA",
      "ResultPath": null
    },
    "EmitirCocinaCompleta": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "EN_COCINA"
        }
      },
      "Retry": [
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "IntervalSeconds": 2,
          "MaxAttempts": 3,
          "BackoffRate": 2
        }
      ],
      "Catch": [
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "Next": "ErrorGeneral",
          "ResultPath": "$.error"
        }
      ],
      "Next": "VerificarStockDespacho",
      "ResultPath": null
    },
    "VerificarStockDespacho": {
      "Type": "Choice",
      "Choices": [
        {
          "Variable": "$.workerId",
          "IsPresent": true,
          "Next": "EN_DESPACHO"
        }
      ],
      "Default": "AsignarWorkerDefault"
    },
    "AsignarWorkerDefault": {
      "Type": "Pass",
      "Result": {
        "workerId": "worker-default"
      },
      "ResultPath": "$.workerAsignado",
      "Next": "EN_DESPACHO"
    },
    "EN_DESPACHO": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke.waitForTaskToken",
      "Parameters": {
        "FunctionName": "${d017b02987a60784aa244e16617956a7}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "EN_DESPACHO",
          "workerId.$": "$.workerId",
          "taskToken.$": "$$.Task.Token"
        }
      },
      "Retry": [
        {
          "ErrorEquals": [
            "Lambda.ServiceException"
          ],
          "IntervalSeconds": 2,
          "MaxAttempts": 2,
          "BackoffRate": 2
        }
      ],
      "Catch": [
        {
          "ErrorEquals": [
            "States.HeartbeatTimeout"
          ],
          "Next": "TimeoutDespacho",
          "ResultPath": "$.error"
        },
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "Next": "ErrorGeneral",
          "ResultPath": "$.error"
        }
      ],
      "HeartbeatSeconds": 3600,
      "Next": "EmitirDespachoCompleto",
      "ResultPath": null
    },
    "TimeoutDespacho": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "TIMEOUT_DESPACHO"
        }
      },
      "Next": "EN_DESPACHO",
      "ResultPath": null
    },
    "EmitirDespachoCompleto": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "EN_DESPACHO"
        }
      },
      "Retry": [
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "IntervalSeconds": 2,
          "MaxAttempts": 3,
          "BackoffRate": 2
        }
      ],
      "Catch": [
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "Next": "ErrorGeneral",
          "ResultPath": "$.error"
        }
      ],
      "Next": "EN_REPARTO",
      "ResultPath": null
    },
    "EN_REPARTO": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke.waitForTaskToken",
      "Parameters": {
        "FunctionName": "${d017b02987a60784aa244e16617956a7}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "EN_REPARTO",
          "workerId.$": "$.workerId",
          "taskToken.$": "$$.Task.Token"
        }
      },
      "Retry": [
        {
          "ErrorEquals": [
            "Lambda.ServiceException"
          ],
          "IntervalSeconds": 2,
          "MaxAttempts": 2,
          "BackoffRate": 2
        }
      ],
      "Catch": [
        {
          "ErrorEquals": [
            "States.HeartbeatTimeout"
          ],
          "Next": "TimeoutReparto",
          "ResultPath": "$.error"
        },
        {
          "ErrorEquals": [
            "States.ALL"
          ],
          "Next": "ErrorGeneral",
          "ResultPath": "$.error"
        }
      ],
      "HeartbeatSeconds": 7200,
      "Next": "EmitirRepartoCompleto",
      "ResultPath": null
    },
    "TimeoutReparto": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "TIMEOUT_REPARTO"
        }
      },
      "Next": "EN_REPARTO",
      "ResultPath": null
    },
    "EmitirRepartoCompleto": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "EN_REPARTO"
        }
      },
      "Next": "FinalizarEntrega",
      "ResultPath": null
    },
    "FinalizarEntrega": {
      "Type": "Parallel",
      "Branches": [
        {
          "StartAt": "RegistrarEntrega",
          "States": {
            "RegistrarEntrega": {
              "Type": "Task",
              "Resource": "arn:aws:states:::lambda:invoke",
              "Parameters": {
                "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
                "Payload": {
                  "orderId.$": "$.orderId",
                  "tenantId.$": "$.tenantId",
                  "estado": "ENTREGADO"
                }
              },
              "End": true,
              "ResultPath": null
            }
          }
        },
        {
          "StartAt": "EsperarConfirmacion",
          "States": {
            "EsperarConfirmacion": {
              "Type": "Wait",
              "Seconds": 3,
              "Next": "EntregaConfirmada"
            },
            "EntregaConfirmada": {
              "Type": "Pass",
              "Result": {
                "confirmacion": "ok"
              },
              "End": true
            }
          }
        }
      ],
      "Next": "ENTREGADO",
      "ResultPath": null
    },
    "ENTREGADO": {
      "Type": "Succeed"
    },
    "ErrorGeneral": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "${e2a6470b743c3ecee83b984ab90412c9}",
        "Payload": {
          "orderId.$": "$.orderId",
          "tenantId.$": "$.tenantId",
          "estado": "ERROR"
        }
      },
      "Next": "FalloCritico",
      "ResultPath": null
    },
    "FalloCritico": {
      "Type": "Fail",
      "Error": "ErrorCritico",
      "Cause": "El workflow encontró un error irrecuperable"
    }
  }
}
